import { Component, h, Listen, Prop, State, Element } from '@stencil/core';
import { NumberFlipperSizes } from './wdpr-number-flipper.model';
import { customTwMerge } from '../../utils/utils';

@Component({
  tag: 'wdpr-number-flipper',
  styleUrl: 'wdpr-number-flipper.css',
  shadow: true,
})
export class WdprNumberFlipper {
  private _observer: MutationObserver;

  @Element() el: HTMLWdprNumberFlipperElement;

  @Prop() size: NumberFlipperSizes = 'small';

  @State() _displayTop: HTMLElement;
  @State() _displayBottom: HTMLElement;
  @State() _overlayTop: HTMLElement;
  @State() _overlayBottom: HTMLElement;
  @State() _isFlipping: boolean = false;

  private getSlotElement(): HTMLElement {
    // Get the assigned nodes of the default slot and return the first element node or a wrapper span if text
    const slot = this.el.shadowRoot.querySelector('slot');
    if (slot) {
      const nodes = (slot as HTMLSlotElement).assignedNodes({ flatten: true });
      for (const node of nodes) {
        if (node.nodeType === Node.ELEMENT_NODE) {
          return node as HTMLElement;
        } else if (node.nodeType === Node.TEXT_NODE && node.textContent.trim()) {
          // Wrap text node in a span for rendering
          const span = document.createElement('span');
          span.textContent = node.textContent;

          return span;
        }
      }
    }

    // Fallback: empty span
    const fallback = document.createElement('span');
    fallback.textContent = '#';

    return fallback;
  }

  // The user came back and the flip was stuck..
  // Force the end state immediately.
  @Listen('visibilitychange')
  handleVisibilityChange() {
    if (document.visibilityState === 'visible' && this._isFlipping) {
      this._handleAnimationEnd();
    }
  }

  componentDidLoad() {
    const slotElement = this.getSlotElement();
    this._displayTop = slotElement;
    this._displayBottom = slotElement.cloneNode(true) as HTMLElement;
    this._overlayTop = slotElement.cloneNode(true) as HTMLElement;
    this._overlayBottom = slotElement.cloneNode(true) as HTMLElement;

    this._observer = new MutationObserver(() => {
      this._handleSlotChange();
    });

    this._observer.observe(this.el, {
      childList: true,
      characterData: true,
      subtree: true,
    });
  }

  disconnectedCallback() {
    this._observer?.disconnect();
  }

  private _handleSlotChange = () => {
    const newElement = this.getSlotElement();
    // Compare outerHTML for change detection
    if (this._displayTop && newElement.outerHTML === this._displayTop.outerHTML) return;

    // We update these values before starting the animation to have a smooth transition between the new and old values.
    this._displayTop = newElement;
    this._overlayBottom = newElement.cloneNode(true) as HTMLElement;
    this._isFlipping = true;
  };

  private get _wrapperClasses(): string {
    return customTwMerge(baseWrapperClasses, sizeClasses[this.size]);
  }

  private _handleAnimationEnd = () => {
    const slotElement = this.getSlotElement();
    this._displayBottom = slotElement.cloneNode(true) as HTMLElement;
    this._overlayTop = slotElement.cloneNode(true) as HTMLElement;
    this._isFlipping = false;
  };

  render() {
    return (
      <div class={this._wrapperClasses}>
        <div class="relative w-full h-full">
          <span class="hidden">
            <slot />
          </span>
          {/* Top half */}
          <span class="top w-full h-1/2 overflow-hidden flex items-end justify-center">
            <span class="z-2" style={{ transform: 'translateY(50%)' }} innerHTML={this._displayTop ? this._displayTop.outerHTML : ''}></span>
          </span>

          {/* Bottom half */}
          <span class="bottom w-full h-1/2 overflow-hidden flex items-start justify-center bg-(--color-plum-050)">
            <span class="z-2" style={{ transform: 'translateY(-50%)' }} innerHTML={this._displayBottom ? this._displayBottom.outerHTML : ''}></span>
          </span>

          {/* Overlay for flip animation */}
          <div class={`overlay${this._isFlipping ? ' flip' : ''} absolute top-0 h-full w-full z-10`} onAnimationEnd={this._handleAnimationEnd}>
            <div class="middle-bar absolute left-0 w-full h-[1px] top-1/2 bg-stroke-default z-11" />

            {/* Overlay Top half */}
            <span class="overlay-top w-full h-1/2 overflow-hidden flex items-end justify-center bg-surface-default origin-bottom">
              <span class="z-12" style={{ transform: 'translateY(50%)' }} innerHTML={this._overlayTop ? this._overlayTop.outerHTML : ''}></span>
            </span>

            {/* Overlay Bottom half */}
            <span class="overlay-bottom w-full h-1/2 overflow-hidden flex items-start justify-center bg-(--color-plum-050) origin-top">
              <span class="z-12" style={{ transform: 'translateY(-50%)' }} innerHTML={this._overlayBottom ? this._overlayBottom.outerHTML : ''}></span>
            </span>
          </div>
        </div>
      </div>
    );
  }
}

const baseWrapperClasses = `border-solid border-012 border-stroke-default
bg-surface-default text-text-heading elevation-xsmall
font-[var(--font-weight-black)] relative overflow-hidden
flex flex-col justify-center items-center`;

const sizeClasses: Record<NumberFlipperSizes, string> = {
  small: 'w-[28px] h-[44px] text-[24px] leading-[26px] tracking--05 rounded-075',
  medium: 'w-[45px] h-[70px] text-[52px] leading-[52px] tracking--05 rounded-125',
  large: 'w-[60px] h-[90px] text-[64px] leading-[64px] tracking--05 rounded-150',
};
